final:
module BCD_counter_4(
   input                clk ,
   input                rst_n,

   output reg [3:0]     obf_Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) obf_Q <= 4'd0;
        else if(obf_Q == 4'd9) obf_Q <= 4'd0;
        else obf_Q <= obf_Q + 4'd1;
    end
endmodule
